/**
 * Build the cursor runtime adapter. Call `.run()` from the hook
 * binary's main(). Generated from specs/typespec/govern/adapters.tsp.
 */
export function createCursorAdapter(config: CursorAdapterConfig) {
  const readStdin = config.readStdin ?? defaultReadStdin;
  const write = config.writeStdout ?? ((data: string) => process.stdout.write(data));
  const exit = config.exit ?? ((code: number) => process.exit(code));

  function writeFallback(shape: string, _v: WorkflowVerdict | undefined | void, env: CursorEnvelope): void {
    const json = renderVerdictOutput(shape as Shape, undefined, env);
    if (json !== undefined) write(JSON.stringify(json));
  }
  function writeVerdict(shape: string, v: WorkflowVerdict | undefined | void, env: CursorEnvelope): void {
    const json = renderVerdictOutput(shape as Shape, v ?? undefined, env);
    if (json !== undefined) write(JSON.stringify(json));
  }

  return {
    async run(): Promise<void> {
      const raw = (await readStdin()).trim();
      if (!raw) return exit(0);
      let env: CursorEnvelope;
      try {
        env = JSON.parse(raw) as CursorEnvelope;
      } catch {
        return exit(0);
      }
      const eventName = (env as unknown as Record<string, unknown>)["hook_event_name"];
      if (typeof eventName !== 'string' || !eventName) return exit(0);

      const { workflowId, runId } = await config.resolveSession(env);
      const session = govern.attach({
        core: config.core,
        preset: presets.cursor,
        workflowId,
        runId,
        approvalPollIntervalMs: 500,
        approvalMaxWaitMs: config.approvalMaxWaitMs,
        onPendingApproval: config.onPendingApproval
          ? (info) => config.onPendingApproval!(info, env)
          : undefined,
        onApprovalResolved: config.onApprovalResolved
          ? (info) => config.onApprovalResolved!(info, env)
          : undefined,
        awaitExternalDecision: config.awaitExternalDecision
          ? (info) => config.awaitExternalDecision!(info, env)
          : undefined,
      });

      const handlers = config.handlers;
      try {
        await dispatch(eventName, env, session, handlers, writeFallback, writeVerdict);
      } finally {
        return exit(0);
      }
    },
  };
}

